@media screen and (max-width:991px){.l-header__close-button{top:var(--vw-size20);right:var(--vw-size16);width:var(--vw-size40);height:var(--vw-size40)}}
.l-header__close-button span{position:absolute;width:var(--vw-size28);height:1px;background-color:#fff}
