.l-header__nav.is-open{transition:transform 1s cubic-bezier(.215,.61,.355,1);transform:translateY(0)}
.l-header__nav.is-close{transition:transform 1s cubic-bezier(.215,.61,.355,1);transform:translateY(-101%)}
