@media screen and (max-width:991px){.l-header__nav-inner{padding:var(--vw-size60) 0}}
.l-header__nav-list li{height:var(--vw-size104);border-bottom:1px solid #1c2230;overflow:hidden}
@media screen and (max-width:991px){.l-header__nav-list li{height:var(--vw-size80)}}
.l-header__nav-list li a{display:flex;align-items:end;gap:var(--vw-size32);height:100%;width:100%;padding:0 var(--vw-size80);padding-bottom:var(--vw-size16);position:relative}
@media screen and (max-width:991px){.l-header__nav-list li a{padding:0 var(--vw-size24);gap:var(--vw-size16)}}
