@media(hover:hover){.l-header__nav-list li a:hover:before{height:100%}.l-header__nav-list li a:hover span{color:#fff!important}}
.l-header__nav-list li a span{z-index:9;transition:color .7s cubic-bezier(.215,.61,.355,1)}
@media screen and (max-width:575px){.l-header__nav-list li a{gap:var(--vw-size8);flex-direction:column;align-items:flex-start;justify-content:end;padding-bottom:var(--vw-size8)}}
