.l-header__nav-list li a .sub{font-size:clamp(1.4rem,1.7vw,2.2rem);font-weight:700;line-height:.85;letter-spacing:.08em;color:#222}
@media screen and (max-width:991px){.l-header__nav-list li a .sub{font-size:clamp(1.4rem,.4vw,1.6rem)}}

